def fermat(n):
    """Returns triplets of the form x^n + y^n = z^n.
    Warning! Untested with n > 2.
    """

    # source: "Fermat's last Python script"
    # https://web.archive.org/web/20200815095147/https://earthboundkid.jottit.com/fermat.py
    # :)

    for x in range(100):
        for y in range(1, x+1):
            for z in range(1, x**n+y**n + 1):
                if x**n + y**n == z**n:
                    yield x, y, z

def generate_random_string(length, using_digits=False, using_ascii_letters=False, using_punctuation=False):  # noqa: FBT002
    """
    Example:
        opting out for 50 symbol-long, [a-z][A-Z][0-9] string
        would yield log_2((26+26+50)^50) ~= 334 bit strength.
    """
    if not using_sysrandom:
        return None

    symbols = []
    if using_digits:
        symbols += string.digits
    if using_ascii_letters:
        symbols += string.ascii_letters
    if using_punctuation:
        all_punctuation = set(string.punctuation)
        # These symbols can cause issues in environment variables
        unsuitable = {"'", '"', "\\", "$"}
        suitable = all_punctuation.difference(unsuitable)
        symbols += "".join(suitable)
    return "".join([random.choice(symbols) for _ in range(length)])

def tables(
    path,
    fts4,
    fts5,
    counts,
    nl,
    arrays,
    csv,
    tsv,
    no_headers,
    table,
    fmt,
    json_cols,
    columns,
    schema,
    load_extension,
    views=False,
):
    """List the tables in the database

    Example:

    \b
        sqlite-utils tables trees.db
    """
    db = sqlite_utils.Database(path)
    _register_db_for_cleanup(db)
    _load_extensions(db, load_extension)
    headers = ["view" if views else "table"]
    if counts:
        headers.append("count")
    if columns:
        headers.append("columns")
    if schema:
        headers.append("schema")

    method = db.view if views else db.table

    def _iter():
        if views:
            items = db.view_names()
        else:
            items = db.table_names(fts4=fts4, fts5=fts5)
        for name in items:
            row = [name]
            if counts:
                row.append(method(name).count)
            if columns:
                cols = [c.name for c in method(name).columns]
                if csv:
                    row.append("\n".join(cols))
                else:
                    row.append(cols)
            if schema:
                row.append(method(name).schema)
            yield row

    if table or fmt:
        print(tabulate.tabulate(_iter(), headers=headers, tablefmt=fmt or "simple"))
    elif csv or tsv:
        writer = csv_std.writer(sys.stdout, dialect="excel-tab" if tsv else "excel")
        if not no_headers:
            writer.writerow(headers)
        for row in _iter():
            writer.writerow(row)
    else:
        for line in output_rows(_iter(), headers, nl, arrays, json_cols):
            click.echo(line)

def wrapper(name: str) -> object:
    """Raise an error if the object is not found, or warn if it was moved.

    In case it was moved, it still returns the object.

    Args:
        name: The object name.

    Returns:
        The object.
    """
    if name == '__path__':
        raise AttributeError(f'module {module!r} has no attribute {name!r}')

    import warnings

    from ._internal._validators import import_string

    import_path = f'{module}:{name}'
    if import_path in MOVED_IN_V2.keys():
        new_location = MOVED_IN_V2[import_path]
        warnings.warn(
            f'`{import_path}` has been moved to `{new_location}`.',
            category=PydanticDeprecatedSince20,
            stacklevel=2,
        )
        return import_string(MOVED_IN_V2[import_path])
    if import_path in DEPRECATED_MOVED_IN_V2:
        # skip the warning here because a deprecation warning will be raised elsewhere
        return import_string(DEPRECATED_MOVED_IN_V2[import_path])
    if import_path in REDIRECT_TO_V1:
        new_location = REDIRECT_TO_V1[import_path]
        warnings.warn(
            f'`{import_path}` has been removed. We are importing from `{new_location}` instead.'
            'See the migration guide for more details: https://docs.pydantic.dev/latest/migration/',
            category=PydanticDeprecatedSince20,
            stacklevel=2,
        )
        return import_string(REDIRECT_TO_V1[import_path])
    if import_path == 'pydantic:BaseSettings':
        raise PydanticImportError(
            '`BaseSettings` has been moved to the `pydantic-settings` package. '
            f'See https://docs.pydantic.dev/{version_short()}/migration/#basesettings-has-moved-to-pydantic-settings '
            'for more details.'
        )
    if import_path in REMOVED_IN_V2:
        raise PydanticImportError(f'`{import_path}` has been removed in V2.')
    globals: dict[str, Any] = sys.modules[module].__dict__
    if name in globals:
        return globals[name]
    raise AttributeError(f'module {module!r} has no attribute {name!r}')
